window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["cdl-tanker"] = window.COURSE_LANG["cdl-tanker"] || {};
window.COURSE_LANG["cdl-tanker"]["es"] = [
  {"id":1,"q":"El chapoteo del líquido (surge) se describe mejor como:","opts":["Líquido que se mueve hacia adelante y atrás o de lado a lado en un tanque parcialmente lleno","Aire que se fuga de las líneas de freno","El tanque que pierde presión poco a poco","Combustible que se mezcla con la carga"],"re":"El surge es el movimiento ondulante del líquido dentro de un tanque parcialmente lleno."},
  {"id":2,"q":"Un chapoteo fuerte del líquido puede afectar:","opts":["La direccion y el frenado","La recepcion de la radio","Solo el consumo de combustible","La presion de las llantas"],"re":"El surge puede empujar el vehiculo y dificultar el control de la direccion y el frenado."},
  {"id":3,"q":"Al detenerte en un cruce, el chapoteo de adelante hacia atras puede:","opts":["Aligerar el eje de direccion","Apagar el motor","Empujar el vehiculo hacia adelante dentro del cruce","Bloquear el freno de estacionamiento"],"re":"Una ola de surge puede empujarte hacia adelante incluso despues de empezar a frenar."},
  {"id":4,"q":"El chapoteo de lado a lado es mas peligroso porque puede:","opts":["Vaciar el tanque","Mejorar la traccion","Enfriar los frenos","Causar una volcadura"],"re":"El surge de lado a lado puede inclinar un tanque alto y causar una volcadura."},
  {"id":5,"q":"Por el surge, la forma mas segura de frenar una cisterna de liquido es:","opts":["Empezar a frenar temprano y con suavidad","Frenar fuerte en el ultimo momento","Bombear los frenos rapido","Ir en neutral por inercia hasta detenerse"],"re":"Frenar temprano y suave evita que la ola de surge empuje el vehiculo."},
  {"id":6,"q":"El surge suele ser mas fuerte cuando el tanque esta:","opts":["Completamente vacio","Parcialmente lleno","Cargado al peso legal","Lleno con un solido"],"re":"Un tanque parcialmente lleno deja espacio para que el liquido se mueva y genere surge."},
  {"id":7,"q":"Al entrar en una curva, el surge puede:","opts":["Acortar tu distancia de seguimiento","Aumentar el agarre de las llantas","Empujar el vehiculo en la direccion en que se mueve el liquido","No tener ningun efecto"],"re":"El liquido en movimiento puede empujar el vehiculo, asi que entra a las curvas despacio y con cuidado."},
  {"id":8,"q":"La mejor respuesta general ante el surge del liquido es:","opts":["Conducir mas rapido para adelantarse","Frenar solo con los frenos del remolque","Mantener el tanque exactamente a la mitad","Ser muy cuidadoso y hacer movimientos suaves y graduales"],"re":"Dirigir, frenar y acelerar de forma suave y gradual mantiene el surge bajo control."},
  {"id":9,"q":"Los bafles dentro de un tanque son mamparas con orificios que:","opts":["Reducen el surge de adelante hacia atras","Calientan la carga","Miden el peso de la carga","Bombean el liquido hacia afuera"],"re":"Los bafles frenan el movimiento del liquido de adelante hacia atras."},
  {"id":10,"q":"Los bafles NO reducen:","opts":["El surge de adelante hacia atras","El surge de lado a lado","La temperatura de la carga","El peso del tanque"],"re":"Los bafles casi no afectan el surge de lado a lado, que puede causar volcadura."},
  {"id":11,"q":"Un tanque de paredes lisas (smooth-bore, sin bafles) tiene:","opts":["Bafles adicionales de lado a lado","Un area de carga dividida","Sin paredes internas ni bafles","Sin valvula de alivio"],"re":"Los tanques de paredes lisas no tienen bafles en su interior."},
  {"id":12,"q":"Los tanques de paredes lisas se caracterizan por:","opts":["No tener nada de surge","Menor riesgo de volcadura","Un centro de gravedad mas bajo","Un fuerte surge de adelante hacia atras"],"re":"Sin bafles, los tanques de paredes lisas tienen un surge de adelante hacia atras muy fuerte."},
  {"id":13,"q":"Los tanques de paredes lisas se usan a menudo para transportar:","opts":["Grava","Productos alimenticios como la leche","Gas comprimido","Cemento seco"],"re":"Los bafles son dificiles de limpiar, por eso cargas de alimentos como la leche suelen usar tanques lisos."},
  {"id":14,"q":"La razon por la que los tanques de alimentos suelen ser de paredes lisas es que:","opts":["Los bafles agregan demasiado peso","Los bafles retrasan mucho la carga","Los bafles son dificiles de limpiar por higiene","Los bafles no se permiten para alimentos"],"re":"Por higiene, los bafles son dificiles de limpiar, asi que muchos tanques de alimentos son lisos."},
  {"id":15,"q":"Al conducir una cisterna de paredes lisas, debes:","opts":["Conducir normal sin cuidado especial","Tener cuidado adicional, sobre todo al arrancar y al frenar","Frenar solo fuerte y tarde","Tomar las rampas a la velocidad indicada"],"re":"El fuerte surge hace que los tanques lisos requieran cuidado extra al arrancar y al frenar."},
  {"id":16,"q":"Comparado con un tanque de paredes lisas, un tanque con bafles suele tener:","opts":["Mas surge de adelante hacia atras","Menos surge de adelante hacia atras","Ninguna valvula de alivio","Un centro de gravedad mas alto"],"re":"Los bafles reducen el surge de adelante hacia atras frente a un tanque liso."},
  {"id":17,"q":"Incluso en un tanque con bafles, aun debes cuidarte del:","opts":["Perdida total de frenado","Que desaparezca todo el surge de adelante hacia atras","Surge de lado a lado","Que el tanque se sobrellene solo"],"re":"Los bafles no detienen el surge de lado a lado, asi que la volcadura sigue siendo un peligro."},
  {"id":18,"q":"El espacio de expansion (outage) es:","opts":["Una fuga en la tapa de la boca","El espacio vacio que se deja para que el liquido se expanda","La capacidad total del tanque","El peso del tanque vacio"],"re":"El outage es el espacio que dejas para que el liquido se expanda al calentarse."},
  {"id":19,"q":"Nunca debes cargar un tanque de liquido:","opts":["A menos de la mitad","En terreno plano","Completamente lleno hasta el tope","Con un bafle instalado"],"re":"Los liquidos se expanden con el calor, asi que debes dejar outage y no llenar por completo."},
  {"id":20,"q":"Distintos liquidos necesitan distinta cantidad de outage porque:","opts":["Cuestan diferente","Pesan todos igual","Nunca cambian de volumen","Se expanden en distinta medida al calentarse"],"re":"Cada liquido se expande de forma distinta, asi que el outage necesario varia."},
  {"id":21,"q":"Con un liquido muy denso (pesado), puede que:","opts":["Llegues al limite legal de peso antes de llenar el tanque","Llenes el tanque por completo siempre","Ignores los limites de peso","Nunca necesites outage"],"re":"Un liquido denso puede alcanzar el limite legal de peso antes de llenar fisicamente el tanque."},
  {"id":22,"q":"Cuanto liquido puedes cargar depende de los limites legales de peso, el peso del liquido y:","opts":["El color del tanque","Cuanto se expandira el liquido (outage)","La configuracion de la radio","El numero de espejos"],"re":"El limite de carga depende del peso, los limites legales y el outage que necesita el liquido."},
  {"id":23,"q":"Si no dejas suficiente outage, el liquido al calentarse puede:","opts":["Encoger el tanque","Bajar el centro de gravedad","Generar presion y desbordarse o fugarse","Mejorar el frenado"],"re":"Sin espacio para expandirse, el liquido puede generar presion y salir a la fuerza."},
  {"id":24,"q":"El outage importa mas cuando la carga va a:","opts":["Mantener exactamente la misma temperatura","Descargarse de inmediato","Viajar solo cuesta abajo","Calentarse durante el viaje"],"re":"Al calentarse el liquido se expande, por eso se necesita espacio de outage."},
  {"id":25,"q":"Conocer el peso del liquido que transportas es importante porque:","opts":["Ajusta el volumen de la radio","Afecta cuanto puedes cargar legalmente","Cambia el color del tanque","No influye en la carga"],"re":"Los liquidos mas pesados alcanzan antes los limites legales, cambiando cuanto puedes cargar."},
  {"id":26,"q":"Los vehiculos cisterna suelen tener un centro de gravedad que es:","opts":["Muy bajo, cerca del suelo","Alto, porque gran parte del peso esta arriba","Siempre en el eje trasero","Justo en el parachoques"],"re":"Gran parte del peso del liquido queda arriba, dando a las cisternas un centro de gravedad alto."},
  {"id":27,"q":"Un centro de gravedad alto significa que el vehiculo es:","opts":["Imposible de volcar","Mejor conducirlo rapido","Pesado por arriba y se vuelca con facilidad","Incapaz de girar"],"re":"Un centro de gravedad alto hace que la cisterna sea pesada por arriba y facil de volcar."},
  {"id":28,"q":"En curvas y rampas de entrada o salida debes conducir:","opts":["Exactamente a la velocidad indicada","Mas rapido que lo indicado para pasarlas pronto","Solo en la marcha mas alta","Muy por debajo de la velocidad indicada"],"re":"Baja muy por debajo de la velocidad indicada en rampas y curvas para no volcar un tanque alto."},
  {"id":29,"q":"La velocidad indicada para una rampa suele ser:","opts":["Segura para una cisterna a plena carga","A menudo demasiado rapida para un tanque alto","La velocidad minima legal","Solo para camiones vacios"],"re":"Las velocidades de rampa se fijan para autos, asi que una cisterna cargada debe ir muy por debajo."},
  {"id":30,"q":"El surge de lado a lado junto con un centro de gravedad alto hace que las cisternas sean propensas a:","opts":["Apagarse el motor","Mejor consumo de combustible","Volcadura","Solo desgaste de llantas"],"re":"Centro de gravedad alto mas surge lateral es una combinacion clasica de volcadura."},
  {"id":31,"q":"Para mantener estable una cisterna pesada por arriba en una curva debes:","opts":["Dirigir y frenar con suavidad y reducir la velocidad antes de la curva","Frenar fuerte en medio de la curva","Acelerar a lo largo de la curva","Girar el volante de golpe"],"re":"Reducir la velocidad antes de la curva y dirigir con suavidad baja el riesgo de volcadura."},
  {"id":32,"q":"Las carreteras mojadas hacen que una cisterna pesada por arriba sea:","opts":["Mas facil de controlar","Mas dificil de controlar y mas propensa a derrapar","Mas baja de centro de gravedad","Inmune al surge"],"re":"Menos traccion en mojado hace mas dificil manejar el surge y la volcadura."},
  {"id":33,"q":"Los movimientos bruscos del volante en una cisterna cargada pueden:","opts":["Bajar el centro de gravedad","Reducir el surge","Iniciar una volcadura","Mejorar el frenado"],"re":"Un giro brusco desplaza la carga alta y puede iniciar una volcadura."},
  {"id":34,"q":"La velocidad mas segura para una curva en una cisterna cargada es:","opts":["La velocidad indicada para la curva","Una velocidad por debajo de la indicada para la curva","Tan rapido como permita el motor","El limite de velocidad de la autopista"],"re":"Toma las curvas por debajo de la velocidad indicada porque el tanque es pesado por arriba."},
  {"id":35,"q":"Al inspeccionar un tanque, lo primero que debes buscar es:","opts":["Fugas","Un tanque de combustible lleno","Espejos limpios","Que la radio funcione"],"re":"Revisa el tanque, las valvulas y las conexiones en busca de fugas antes de conducir."},
  {"id":36,"q":"Debes inspeccionar la valvula de alivio de vapor o presion para asegurarte de que este:","opts":["Pintada del color correcto","Funcionando y sin atascarse","Retirada antes de conducir","Llena de aceite"],"re":"La valvula de alivio debe funcionar para que el tanque libere presion de forma segura."},
  {"id":37,"q":"Las tapas de la boca (domo) y sus juntas deben revisarse porque:","opts":["Muestran el peso del tanque","Controlan los frenos","Una fuga ahi puede derramar la carga","Fijan la velocidad"],"re":"Tapas o juntas sueltas o gastadas pueden dejar escapar liquido o vapor."},
  {"id":38,"q":"Cual de estos debe inspeccionarse en un vehiculo cisterna?","opts":["El seguro de la guantera","La tela del asiento","La antena de la radio","Las valvulas de entrada, descarga y corte"],"re":"Las valvulas de entrada, descarga y corte deben revisarse por fugas y danos."},
  {"id":39,"q":"Las tuberias y mangueras de un tanque deben revisarse por:","opts":["Fugas y danos","Pintura correcta","Marcas comerciales","Dibujo de la llanta"],"re":"Inspecciona tuberias y mangueras por fugas, desgaste y danos antes de conducir."},
  {"id":40,"q":"El equipo especial que acompana al tanque (como mangueras y conexiones) debe estar:","opts":["Presente y en buen estado","Dejado atras","Pintado de rojo brillante","Retirado para ahorrar peso"],"re":"Verifica que el equipo especial requerido este presente y en buen estado."},
  {"id":41,"q":"Si encuentras una fuga durante la inspeccion del tanque, debes:","opts":["Conducir con cuidado y arreglarla despues","Ignorar las fugas pequenas","No conducir hasta que este reparada","Taparla con cinta y seguir"],"re":"Un tanque con fugas es inseguro; no conduzcas hasta repararla."},
  {"id":42,"q":"Revisar el cuerpo y las cabezas (extremos) del tanque por abolladuras o grietas es importante porque:","opts":["El dano puede debilitar el tanque y causar fugas","Cambia el color","Fija el peso de carga","Mejora la radio"],"re":"Las abolladuras y grietas pueden debilitar el tanque y provocar fugas o fallas."},
  {"id":43,"q":"Para controlar el surge al conducir, debes:","opts":["Frenar, acelerar y dirigir de forma suave y gradual","Hacer movimientos rapidos y bruscos","Frenar solo en el ultimo segundo","Cambiar de carril constantemente"],"re":"Acciones suaves y graduales evitan que el liquido haga surge fuerte."},
  {"id":44,"q":"En una curva o emergencia, debes evitar:","opts":["Sobredirigir (girar demasiado brusco)","Mirar hacia adelante","Reducir la velocidad con tiempo","Mantener ambas manos en el volante"],"re":"Sobredirigir puede desplazar la carga e iniciar un derrape o una volcadura."},
  {"id":45,"q":"Si tu cisterna empieza a derrapar, debes:","opts":["Frenar fuerte y mantenerlo","Girar bruscamente hacia el otro lado","Acelerar para enderezar","Recuperar el control con suavidad"],"re":"Una recuperacion suave ayuda a retomar el control sin empeorar el surge."},
  {"id":46,"q":"En comparacion con otros vehiculos, una cisterna cargada debe mantener:","opts":["Una distancia de seguimiento menor","Ninguna distancia de seguimiento","La misma distancia solo cuando esta vacia","Una distancia de seguimiento mayor"],"re":"El surge y la mayor distancia de frenado hacen que la cisterna mantenga mas distancia."},
  {"id":47,"q":"Cuando aceleras una cisterna de liquido, debes hacerlo:","opts":["Lo mas fuerte posible","Solo en reversa","Mientras frenas","De forma suave y gradual"],"re":"Una aceleracion suave evita que el liquido haga surge hacia adelante y atras."},
  {"id":48,"q":"Una cisterna vacia comparada con una cargada:","opts":["Siempre se maneja exactamente igual","Nunca puede volcarse","No necesita distancia de seguimiento","Puede manejarse distinto y aun requiere cuidado"],"re":"Los tanques vacios y cargados se manejan distinto, asi que mantente alerta en ambos casos."},
  {"id":49,"q":"En una carretera resbaladiza, el conductor de una cisterna debe:","opts":["Conducir mas rapido para salir pronto","Seguir de cerca para aprovechar el rebufo","Frenar fuerte con frecuencia","Reducir la velocidad y aumentar la distancia de seguimiento"],"re":"Reducir la velocidad y dejar mas espacio ayuda con el surge y la menor traccion."},
  {"id":50,"q":"Si debes hacer una maniobra de emergencia en una cisterna, recuerda que la carga puede:","opts":["Desaparecer por si sola","Hacer el tanque mas ligero","Eliminar todo riesgo de volcadura","Hacer surge y empujar el vehiculo, asi que actua con suavidad"],"re":"Incluso en emergencia, el surge puede empujar el vehiculo, asi que manten los movimientos suaves y controlados."}
];
